import math

class GaussianNB:
    def fit(self, X, y):
        classes  = list(set(y))
        self.classes_ = classes
        n, d     = len(X), len(X[0])
        self.log_prior_ = {}
        self.mean_  = {}
        self.var_   = {}
        for c in classes:
            Xc = [X[i] for i in range(n) if y[i] == c]
            nc = len(Xc)
            self.log_prior_[c] = math.log(nc / n)
            self.mean_[c]  = [sum(Xc[i][j] for i in range(nc))/nc for j in range(d)]
            self.var_[c]   = [max(1e-9, sum((Xc[i][j]-self.mean_[c][j])**2
                              for i in range(nc))/nc) for j in range(d)]
